INSERT INTO NOTICE_IMG (
	ORIGIN_IMG_NAME
	, ATTACHED_IMG_NAME
	, NOTICE_ID
) VALUES

(
	#{noticeImg.originImgName}
	, #{noticeImg.attachedImgName}
	, #{noticeImg.noticeId}
)

mapper.select:
SELECT COUNT(IMG_NUM)
FROM NOTICE_IMG
WHERE NOTICE_ID = #{noticeId}

SELECT N.NOTICE_ID , NOTICE_TITLE , USER_ID , NOTICE_DATE , IS_IMPORTANT , IFNULL(IMG_NUM, 0) IMG_NUM FROM NOTICE N LEFT JOIN NOTICE_IMG I ON N.NOTICE_ID = I.NOTICE_ID WHERE 1 = 1
AND N.NOTICE_ID = #{noticeId}
AND NOTICE_TITLE LIKE CONCAT('%', #{noticeTitle}, '%')
AND USER_ID LIKE CONCAT('%', #{userId}, '%')
AND TO_CHAR(NOTICE_DATE, 'YYYY-MM-DD') = #{noticeDate}
ORDER BY IS_IMPORTANT DESC, NOTICE_DATE DESC

mapper.update:
UPDATE NOTICE
SET NOTICE_TITLE = #{noticeTitle}
	, NOTICE_CONTENT = #{noticeContent}
	, IS_IMPORTANT = #{isImportant}
WHERE NOTICE_ID = #{noticeId}

mapper.select:
SELECT ATTACHED_IMG_NAME
FROM NOTICE_IMG
WHERE NOTICE_ID = #{noticeId}

